/* prototype.css — demo - 副本 */
/* 完全内联样式，无远程依赖，无全局选择器 */

/* 重置以原型页根容器为作用域 */
.page-wrapper,
.page-wrapper *,
.page-wrapper *::before,
.page-wrapper *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

.page-wrapper {
  width: 100%;
  height: 100vh;
  overflow: hidden;
  position: relative;
  background: #fff;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC", "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
}

/* 可滑动内容区域 */
.scroll-content {
  position: absolute;
  inset: 0;
  overflow-y: auto;
  overflow-x: hidden;
}

/* 隐藏滚动条 */
.scroll-content::-webkit-scrollbar {
  display: none;
  width: 0;
  height: 0;
}
.scroll-content {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

/* 页面容器 */
.page-container {
  width: 1133px;
  min-height: 100vh;
  position: relative;
  margin: 0 auto;
  background: #fff;
}

/* 装饰背景图 */
.deco-bg {
  position: absolute;
  left: 177px;
  top: 20px;
  width: 780px;
  height: 527px;
  object-fit: cover;
}

/* 邀友得奖模块 */
.section-invite {
  position: absolute;
  left: 177px;
  top: 587px;
  width: 780px;
  display: inline-flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 20px;
}

/* 叫叫商城模块 */
.section-mall {
  position: absolute;
  left: 177px;
  top: 761px;
  width: 780px;
  display: inline-flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 20px;
}

/* 模块头部 */
.section-header {
  width: 100%;
  height: 34px;
  padding: 0 4px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-shrink: 0;
}

.section-title {
  color: #666;
  font-size: 22.5px;
  font-weight: 500;
  line-height: 33.75px;
  white-space: nowrap;
  flex-shrink: 0;
}

.section-more {
  display: flex;
  justify-content: flex-end;
  align-items: center;
  flex-shrink: 0;
  gap: 2px;
}

.section-more-hidden {
  opacity: 0;
  pointer-events: none;
}

.section-more-text {
  color: #b2b2b2;
  font-size: 18px;
  font-weight: 400;
  line-height: 27px;
  white-space: nowrap;
  text-align: right;
}

.section-more-hidden .section-more-text {
  color: #acb2bb;
}

/* 卡片行 */
.card-row {
  align-self: stretch;
  display: inline-flex;
  justify-content: flex-start;
  align-items: center;
  gap: 10px;
  flex-shrink: 0;
}

/* 单个卡片 */
.card {
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  width: 385px;
  height: 80px;
  border-radius: 20px;
}

.card img {
  height: 100%;
  width: auto;
  object-fit: contain;
}

/* 底部 Logo 区域 */
.logo-section {
  position: absolute;
  left: 177px;
  top: 915px;
  width: 780px;
  padding: 24px 10px;
  display: inline-flex;
  flex-direction: column;
  justify-content: flex-end;
  align-items: center;
  gap: 10px;
}

.logo-img {
  width: 156.98px;
  height: 39.85px;
  flex-shrink: 0;
}

/* 底部广告图 */
.bottom-ad {
  position: absolute;
  left: 0;
  top: 1024px;
  width: 1133px;
}

.bottom-ad img {
  width: 100%;
  object-fit: contain;
  display: block;
}

/* 固定顶部导航栏 */
.fixed-top {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 1133px;
  z-index: 10;
  pointer-events: none;
}

.fixed-top img {
  width: 100%;
  object-fit: cover;
  height: 20px;
  display: block;
}

/* 固定底部标签栏 */
.fixed-bottom {
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 1133px;
  z-index: 10;
  pointer-events: none;
}

.fixed-bottom img {
  width: 100%;
  object-fit: contain;
  display: block;
}

